{
  "mode": "method",
  "tests": [
    {
      "name": "valid_application_bangalore",
      "input": {
        "location": "Bangalore",
        "duration": 12,
        "working_hours": 8.5
      },
      "output": "Application accepted",
      "notes": "Valid application from a candidate based in Bangalore."
    },
    {
      "name": "valid_application_chennai",
      "input": {
        "location": "Chennai",
        "duration": 8,
        "working_hours": 8.5
      },
      "output": "Application accepted",
      "notes": "Valid application from a candidate based in Chennai."
    },
    {
      "name": "invalid_application_outside_location",
      "input": {
        "location": "Mumbai",
        "duration": 10,
        "working_hours": 8.5
      },
      "output": "Application rejected",
      "notes": "Invalid application from a candidate outside the specified locations."
    },
    {
      "name": "invalid_application_duration_too_short",
      "input": {
        "location": "Bangalore",
        "duration": 3,
        "working_hours": 8.5
      },
      "output": "Application rejected",
      "notes": "Invalid application with a duration less than the minimum requirement."
    },
    {
      "name": "invalid_application_duration_too_long",
      "input": {
        "location": "Chennai",
        "duration": 20,
        "working_hours": 8.5
      },
      "output": "Application rejected",
      "notes": "Invalid application with a duration exceeding the maximum requirement."
    },
    {
      "name": "valid_application_relocation",
      "input": {
        "location": "Delhi",
        "willing_to_relocate": true,
        "duration": 10,
        "working_hours": 8.5
      },
      "output": "Application accepted",
      "notes": "Valid application from a candidate willing to relocate to Bangalore or Chennai."
    },
    {
      "name": "invalid_application_no_relocation",
      "input": {
        "location": "Delhi",
        "willing_to_relocate": false,
        "duration": 10,
        "working_hours": 8.5
      },
      "output": "Application rejected",
      "notes": "Invalid application from a candidate not willing to relocate."
    },
    {
      "name": "valid_application_edge_case_max_duration",
      "input": {
        "location": "Bangalore",
        "duration": 16,
        "working_hours": 8.5
      },
      "output": "Application accepted",
      "notes": "Valid application with maximum duration allowed."
    }
  ],
  "assumptions": "Candidates must meet location and duration requirements.",
  "notes": "Ensure to validate relocation willingness for candidates outside specified locations."
}
